<script setup lang="ts">
import { computed, onMounted, ref, watch } from 'vue'; import { useRoute } from 'vue-router'; import { serviceApi } from '@/api/services'; import PageState from '@/shared/PageState.vue'; import { bytes,date } from '@/shared/format'
const route=useRoute(),loading=ref(true),error=ref(''),data=ref<any>(null);const kind=computed(()=>String(route.meta.kind));const meta:Record<string,[string,string]>= {invite:['我的邀请','管理邀请码并查看返佣记录'],traffic:['流量明细','近一个月的流量使用记录'],servers:['节点状态','查看可用节点和连接倍率'],knowledge:['使用文档','客户端配置与常见问题'],gifts:['礼品卡','兑换礼品卡并查看历史记录']}
async function load(){loading.value=true;error.value='';try{data.value=await ({invite:serviceApi.inviteDetails,traffic:serviceApi.traffic,servers:serviceApi.servers,knowledge:serviceApi.knowledge,gifts:serviceApi.giftHistory}[kind.value]||serviceApi.knowledge)()}catch(e:any){error.value=e.message}finally{loading.value=false}}onMounted(load);watch(kind,load)
const rows=computed(()=>Array.isArray(data.value)?data.value:data.value?.data||data.value?.records||[])
</script>
<template><PageState :loading="loading" :error="error" @retry="load"><div class="page-heading"><div><h1>{{meta[kind]?.[0]}}</h1><p>{{meta[kind]?.[1]}}</p></div></div><section v-if="kind==='invite'" class="stats-strip"><div><small>已注册用户</small><strong>{{data?.stat?.[0]||data?.registered_users||0}}</strong></div><div><small>累计佣金</small><strong>{{data?.stat?.[1]||data?.commission||0}}</strong></div><div><small>佣金比例</small><strong>{{data?.commission_rate||0}}%</strong></div></section><section class="panel data-list"><article v-for="(item,index) in rows" :key="item.id||index"><div><strong>{{item.name||item.title||item.email||item.code||`记录 ${index+1}`}}</strong><p>{{item.category?.name||item.message||item.ip||item.server_name||item.description||''}}</p></div><div><span v-if="item.rate" class="status">倍率 {{item.rate}}</span><span v-if="item.u||item.d">{{bytes(Number(item.u||0)+Number(item.d||0))}}</span><time>{{date(item.created_at||item.updated_at,true)}}</time></div></article><div v-if="!rows.length" class="page-state">暂无数据</div></section></PageState></template>
